# Resource: данные по URI; шаблон с параметром
@mcp.resource("report://{month}")
def monthly_report(month: str) -> str:
    """Отчёт о продажах за месяц в формате Markdown."""
    return load_report(month)

# Prompt: шаблон, который пользователь вызывает сам
@mcp.prompt()
def weekly_report() -> str:
    """Собрать еженедельный отчёт по шаблону команды."""
    return (
        "Собери отчёт за неделю: возьми данные инструментом "
        "get_sales, сгруппируй по регионам и оформи таблицей "
        "с колонками: регион, продажи, динамика к прошлой неделе."
    )

@mcp.tool()
def get_sales(month: str) -> str:
    """Продажи за месяц. month — в формате ГГГГ-ММ, например 2026-07."""
    if not re.fullmatch(r"\d{4}-\d{2}", month):
        return f"Ошибка: месяц должен быть в формате ГГГГ-ММ (получено: {month}). Переформулируй запрос."
    try:
        return fetch_sales(month)
    except ConnectionError:
        return "Ошибка: база данных недоступна. Сообщи пользователю и предложи повторить позже."
